// Java Kafka producer tuned for high throughput
Properties props = new Properties();
props.put("bootstrap.servers", "kafka1:9092,kafka2:9092");
props.put("acks", "all"); // durable
props.put("compression.type", "lz4");
props.put("linger.ms", "50"); // wait up to 50ms to batch
props.put("batch.size", 65536); // 64KB
props.put("buffer.memory", 33554432);
props.put("key.serializer", "org.apache.kafka.common.serialization.StringSerializer");
props.put("value.serializer", "org.apache.kafka.common.serialization.ByteArraySerializer");

KafkaProducer<String, byte[]> producer = new KafkaProducer<>(props);
ProducerRecord<String, byte[]> rec = new ProducerRecord<>("user-activity", key, payload);
producer.send(rec, (metadata, exception) -> {
  if (exception != null) {
    // handle failure (retry logic, alerts)
  }
});

