/* Quick Postgres checklist: examine plan, add index, re-check */
-- 1) Inspect the plan
EXPLAIN ANALYZE SELECT id FROM orders WHERE customer_id = 123 AND status = 'shipped';

-- 2) If planner chooses seq scan, add a composite index tailored to the query
CREATE INDEX CONCURRENTLY idx_orders_customer_status ON orders (customer_id, status);

-- 3) Re-run and verify
EXPLAIN ANALYZE SELECT id FROM orders WHERE customer_id = 123 AND status = 'shipped';

-- 4) For case-insensitive searches, use a functional index
CREATE INDEX CONCURRENTLY idx_users_lower_email ON users (LOWER(email));
